import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int count = 0;
        for (int a = 1; a <= n; a++) {
            for (int b = a; b <= n; b++) {
                int c2 = a*a + b*b;
                int c = (int)Math.sqrt(c2);
                if (c*c == c2 && c <= n) count++;
            }
        }
        System.out.println(count);
    }
