def number_of_right_triangles(grid):
    m, n = len(grid), len(grid[0])
    row_cnt = [sum(row) for row in grid]
    col_cnt = [sum(grid[i][j] for i in range(m)) for j in range(n)]

    ans = 0
    for i in range(m):
        for j in range(n):
            if grid[i][j] == 1:
                ans += (row_cnt[i] - 1) * (col_cnt[j] - 1)
    return ans
